<?php
$giftTotals=[];
foreach($totals['items'] as $cartItem){$giftCustom=json_decode((string)($cartItem['customization_json']??''),true)?:[];if(($giftCustom['type']??'')==='gift_box'&&!empty($giftCustom['group'])){$giftTotals[(string)$giftCustom['group']]=($giftTotals[(string)$giftCustom['group']]??0)+((int)$cartItem['price_minor']*(int)$cartItem['quantity']);}}
?>
<?php if (!$totals['items']): ?><div class="empty-state compact"><p>Coșul tău așteaptă prima alegere.</p><a class="button" href="<?= e(url('/shop')) ?>">Descoperă colecția</a></div><?php else: ?><div class="drawer-items"><?php foreach ($totals['items'] as $item): $custom=json_decode((string)($item['customization_json']??''),true)?:[]; if(($custom['type']??'')==='gift_box'&&($custom['role']??'')==='component') continue; $isGiftBox=($custom['type']??'')==='gift_box'&&($custom['role']??'')==='box'; $group=(string)($custom['group']??''); ?><div class="drawer-item <?= $isGiftBox?'drawer-item-gift-box':'' ?>"><img src="<?= e(url($item['image_path'])) ?>" alt="" width="72" height="86"><div><strong><?= e($isGiftBox?($custom['template_name']??$item['name']):$item['name']) ?></strong><?php if($isGiftBox): ?><small>Gift Box · <?= count((array)($custom['components']??[])) ?> produse</small><?php if(!empty($custom['recipient_name'])): ?><small>Destinatar: <?= e($custom['recipient_name']) ?></small><?php endif; ?><?php if(!empty($custom['gift_message'])): ?><small class="gift-cart-message">„<?= e($custom['gift_message']) ?>”</small><?php endif; ?><?php else: ?><small><?= e($item['variant_label'] ?: 'Standard') ?> · <?= (int)$item['quantity'] ?> buc.</small><?php endif; ?></div><b><?= money($isGiftBox?($giftTotals[$group]??0):((int)$item['price_minor']*(int)$item['quantity'])) ?></b></div><?php endforeach; ?></div><div class="drawer-total"><span>Subtotal</span><strong><?= money($totals['subtotal_minor']) ?></strong></div><a class="button" href="<?= e(url('/checkout')) ?>">Finalizează comanda</a><a class="button button-outline" href="<?= e(url('/cos')) ?>">Vezi coșul</a><?php endif; ?>